import{_ as t,o,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"78. Health Service Obligations","description":"","frontmatter":{"title":"78. Health Service Obligations","eba":"Doctors in Training 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/union-matters/78-health-service-obligations.md","filePath":"ebas/doctors-in-training/union-matters/78-health-service-obligations.md"}'),s={name:"ebas/doctors-in-training/union-matters/78-health-service-obligations.md"};function n(a,e,h,c,l,p){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_78-health-service-obligations" tabindex="-1">78. Health Service Obligations <a class="header-anchor" href="#_78-health-service-obligations" aria-label="Permalink to &quot;78. Health Service Obligations&quot;">​</a></h1><p><strong>78.1</strong> A Health Service must not dismiss, threaten to dismiss, injure or threaten to injure a Doctor in respect of his or her employment nor alter the Doctor&#39;s position, or threaten to alter the position to the Doctor&#39;s detriment for the following reasons:</p><p><strong>(a)</strong> the Doctor has been, is, or proposes to become an Officer, delegate or member of the Association; or</p><p><strong>(b)</strong> the Doctor is entitled to the benefits of the Agreement, or has asked to receive the benefit; or</p><p><strong>(c)</strong> the Doctor has appeared, or proposes to appear, as a witness, or has given or proposes to give evidence in a proceeding under the Act; or</p><p><strong>(d)</strong> the Doctor, being a member of the Association which is seeking better industrial conditions, is dissatisfied with employment conditions; or</p><p><strong>(e)</strong> the Doctor was absent from rostered duty because:</p><p><strong>(i)</strong> the absence was for the purpose of carrying out duties or exercising rights as an Officer or delegate of the Association; or</p><p><strong>(ii)</strong> the Doctor applied for leave before the absence referred to in subclause 78.1(e)(i) above and the Health Service unreasonably refused or withheld consent for the leave.</p><p><strong>(f)</strong> The Officer, delegate or member of the Association has done or proposes to do an act or thing which is lawful for the purpose of furthering or protecting the industrial interests of the Association or its members. The act or thing must be done within the limits of authority expressly conferred on the Doctor by the Association in accordance with the rules of the Association.</p><p><strong>(g)</strong> The absences referred to above must not exceed a period of five consecutive working days or a total of five working days in any four week period without a written request from the officer of the Association. Authorisation of any such absence must not be unreasonably withheld by the Health Service. Provided sufficient and appropriate notice is given, the onus is placed on the Health Service to explain the circumstances of any refusal to release the Doctor from duty as expeditiously as possible.</p><p><strong>(h)</strong> The absences referred to above must be without pay unless otherwise agreed to by the Health Service.</p><p>Plain language terms: employer obligations.</p>',13)])])}const f=t(s,[["render",n]]);export{g as __pageData,f as default};
